// Normalizar payload de diferentes provedores de pagamento
// Compatível com: Cell Coin, Asaas, Pagar.me, MercadoPago
const body = $json;

let leadId, valor, metodo, status, transacaoId, provedor;

// Cell Coin (formato principal)
if (body.event && (body.event.includes('payment') || body.event.includes('PAYMENT'))) {
  provedor = 'cellcoin';
  const data = body.data || body.payload || {};
  leadId = data.externalId || data.external_id || data.referenceId;
  valor = data.amount || data.value || 0;
  const tipo = (data.paymentType || data.type || '').toLowerCase();
  if (tipo.includes('pix')) metodo = 'pix';
  else if (tipo.includes('boleto') || tipo.includes('bank_slip')) metodo = 'boleto';
  else if (tipo.includes('card') || tipo.includes('credit') || tipo.includes('debit')) metodo = 'cartao';
  else metodo = 'pix';
  const evt = (body.event || '').toUpperCase();
  status = (evt.includes('CONFIRMED') || evt.includes('PAID') || evt.includes('APPROVED')) ? 'CONFIRMED' : evt;
  transacaoId = data.transactionId || data.id || body.id;

// Asaas
} else if (body.payment) {
  provedor = 'asaas';
  leadId = body.payment.externalReference || body.payment.description?.match(/lead:([a-z0-9-]+)/)?.[1];
  valor = body.payment.value;
  const bt = (body.payment.billingType || '').toLowerCase();
  if (bt === 'pix') metodo = 'pix';
  else if (bt === 'boleto') metodo = 'boleto';
  else if (bt === 'credit_card') metodo = 'cartao';
  else metodo = 'pix';
  status = body.payment.status;
  transacaoId = body.payment.id;

// Pagar.me
} else if (body.current_status) {
  provedor = 'pagarme';
  leadId = body.metadata?.lead_id;
  valor = (body.amount || 0) / 100;
  const pm = (body.payment_method || '').toLowerCase();
  if (pm === 'pix') metodo = 'pix';
  else if (pm === 'boleto') metodo = 'boleto';
  else metodo = 'cartao';
  status = body.current_status === 'paid' ? 'CONFIRMED' : body.current_status;
  transacaoId = body.id;

// MercadoPago
} else if (body.action?.includes('payment')) {
  provedor = 'mercadopago';
  leadId = body.data?.metadata?.lead_id;
  valor = body.data?.transaction_amount;
  metodo = 'cartao';
  status = body.data?.status === 'approved' ? 'CONFIRMED' : body.data?.status;
  transacaoId = body.data?.id?.toString();
}

// Verificar se pagamento foi confirmado
const confirmado = ['CONFIRMED', 'RECEIVED', 'paid', 'approved', 'PAID', 'APPROVED'].includes(status);

return [{
  json: {
    leadId,
    valor: parseFloat(valor) || 0,
    metodo: metodo || 'pix',
    status,
    transacaoId,
    provedor,
    confirmado,
    timestamp: new Date().toISOString(),
  }
}];

// Montar mensagem de confirmação para o cliente
const lead = $('Atualizar Lead — Status Pago').first().json;
const pagamento = $('Normalizar Payload do Provedor').first().json;

const valorPago = new Intl.NumberFormat('pt-BR', {style:'currency',currency:'BRL'}).format(pagamento.valor || 0);
const nome = (lead.nome || '').split(' ')[0];

const mensagem = `Parabéns, ${nome}! Seu pagamento de ${valorPago} foi confirmado. Seus benefícios Plano Mais estão ativos. Obrigado por regularizar! Qualquer dúvida, estamos aqui.`;

return [{
  json: {
    telefone: lead.telefone,
    email: lead.email,
    nome: lead.nome,
    mensagem,
    valorPago,
    leadId: pagamento.leadId,
  }
}];
